/**
 * @name NameServer updateConfig - network data applied to config without auth check
 * @description DefaultRequestProcessor.updateConfig allows updating NameServer config via network
 *              which may set rocketmqHome used in subsequent shell commands (CVE-2023-37582)
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-namesrv-updateconfig-rce
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module NamesrvUpdateConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: MixAll.string2File, System.setProperty, or other side-effecting calls
    // in the namesrv DefaultRequestProcessor.updateConfig path
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("string2File") and
        mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.common", "MixAll")
        or
        mc.getMethod().hasName("setProperty") and
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "System")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

